// The ensures of this synthetic det_ fn is an implication of the form
// (big_conjunction_of_post_ensures) ==> det_kill_running_thread_equal(...).
// In the prior attempt the prelude asserted conjuncts of the antecedent
// directly (e.g. `assert(post1_self_.wf())`), which Verus rejects because
// those facts are *not* in the proof context — they live inside the
// antecedent of the ensures implication. The repair is to introduce the
// antecedent explicitly via an `if` guard; inside the `if` branch Verus
// treats every conjunct as a known hypothesis, and after the `if` merges
// the verifier knows "antecedent ==> (everything we asserted in the
// branch)", which is exactly the implication we owe.
if ({
    &&& (post1_self_.wf())
    &&& (post1_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr))
    &&& (threads_unchanged_except(pre_self_, post1_self_, set![]))
    &&& (post1_self_.proc_dom() == pre_self_.proc_dom())
    &&& (process_tree_unchanged(pre_self_, post1_self_))
    &&& (post1_self_.container_dom() == pre_self_.container_dom())
    &&& (containers_tree_unchanged(pre_self_, post1_self_))
    &&& (post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@
          == pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@.remove_value(thread_ptr))
    &&& (post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len()
          == pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len() - 1)
    &&& (process_mem_unchanged(pre_self_, post1_self_))
    &&& (post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0))
    &&& (pre_self_.page_closure().contains(r1.0))
    &&& (r1.0 == r1.1@.addr())
    &&& (r1.1@.is_init())
    &&& (pre_self_.container_dom().contains(r1.0) == false)
    &&& (post2_self_.wf())
    &&& (post2_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr))
    &&& (threads_unchanged_except(pre_self_, post2_self_, set![]))
    &&& (post2_self_.proc_dom() == pre_self_.proc_dom())
    &&& (process_tree_unchanged(pre_self_, post2_self_))
    &&& (post2_self_.container_dom() == pre_self_.container_dom())
    &&& (containers_tree_unchanged(pre_self_, post2_self_))
    &&& (post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@
          == pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@.remove_value(thread_ptr))
    &&& (post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len()
          == pre_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len() - 1)
    &&& (process_mem_unchanged(pre_self_, post2_self_))
    &&& (post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0))
    &&& (pre_self_.page_closure().contains(r2.0))
    &&& (r2.0 == r2.1@.addr())
    &&& (r2.1@.is_init())
    &&& (pre_self_.container_dom().contains(r2.0) == false)
}) {
    // Antecedent now in scope. Re-assert every conjunct so each ensures
    // trigger fires on both the post1 and post2 sides.
    assert(post1_self_.wf());
    assert(post1_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr));
    assert(threads_unchanged_except(pre_self_, post1_self_, set![]));
    assert(post1_self_.proc_dom() == pre_self_.proc_dom());
    assert(process_tree_unchanged(pre_self_, post1_self_));
    assert(post1_self_.container_dom() == pre_self_.container_dom());
    assert(containers_tree_unchanged(pre_self_, post1_self_));
    assert(process_mem_unchanged(pre_self_, post1_self_));
    assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0));
    assert(pre_self_.page_closure().contains(r1.0));
    assert(r1.0 == r1.1@.addr());
    assert(r1.1@.is_init());
    assert(pre_self_.container_dom().contains(r1.0) == false);

    assert(post2_self_.wf());
    assert(post2_self_.thread_dom() == pre_self_.thread_dom().remove(thread_ptr));
    assert(threads_unchanged_except(pre_self_, post2_self_, set![]));
    assert(post2_self_.proc_dom() == pre_self_.proc_dom());
    assert(process_tree_unchanged(pre_self_, post2_self_));
    assert(post2_self_.container_dom() == pre_self_.container_dom());
    assert(containers_tree_unchanged(pre_self_, post2_self_));
    assert(process_mem_unchanged(pre_self_, post2_self_));
    assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0));
    assert(pre_self_.page_closure().contains(r2.0));
    assert(r2.0 == r2.1@.addr());
    assert(r2.1@.is_init());
    assert(pre_self_.container_dom().contains(r2.0) == false);

    // Cross-side domain equalities: every domain pinned to a pre_self_ expression
    // is identical on both sides via transitivity.
    assert(post1_self_.thread_dom() =~= post2_self_.thread_dom());
    assert(post1_self_.proc_dom() =~= post2_self_.proc_dom());
    assert(post1_self_.container_dom() =~= post2_self_.container_dom());

    // Re-state the page_closure constraints together so z3 sees the shared
    // structure of `pre_self_.page_closure().remove(_)`.
    assert(post1_self_.page_closure() =~= pre_self_.page_closure().remove(r1.0));
    assert(post2_self_.page_closure() =~= pre_self_.page_closure().remove(r2.0));

    // Cross-side equalities for the owned_threads sequence on the owning proc.
    assert(post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@
        =~= post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads@);
    assert(post1_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len()
        == post2_self_.get_proc(pre_self_.get_thread(thread_ptr).owning_proc).owned_threads.len());

    // Tuple-level page-pointer / permission view sanity for each side.
    assert(r1.0 == r1.1@.addr());
    assert(r2.0 == r2.1@.addr());
}
